- 'Modified' refers to changes recorded in the audit trail with a timestamp; 
- 'specific user with ID 1' refers to the user with a unique identifier of 1 in the users table; 
- 'default annotation' refers to the annotation with an annotation_id of 0 in the field_annotations table.

sql:
SELECT COUNT(DISTINCT simulation_id) 
FROM timeline_simulations 
WHERE updated_at IS NULL;

SELECT name 
FROM plugins 
WHERE updated_at = '2023-05-01 12:00:00';

SELECT MAX(updated_at) AS last_update_timestamp
FROM plugins
WHERE plugin_id = 0;

SELECT instance_id 
FROM plugin_instances 
WHERE field_id = 0;

SELECT name, description
FROM data_fields
WHERE required = 1 AND min = 5;

SELECT name
FROM plugins
WHERE plugin_id = 1;

SELECT instance_id, configuration 
FROM plugin_instances 
WHERE plugin_id = (SELECT plugin_id FROM plugins WHERE name = 'RandomString');

SELECT df.name AS field_name, ts.simulation_id, ts.update_percentage
FROM data_fields df
INNER JOIN timeline_simulations ts ON df.field_id = ts.field_id;

SELECT DISTINCT role_name
FROM roles
WHERE created_at BETWEEN '2023-01-01' AND '2023-12-31';

SELECT 
    (SELECT COUNT(DISTINCT plugin_id) FROM plugins) AS plugin_count,
    (SELECT COUNT(instance_id) FROM plugin_instances) AS instance_count;
